import{_ as t,c as o,o as n,ae as s}from"./chunks/framework.BvcDoAct.js";const E=JSON.parse('{"title":"BE:FIRST","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/02_Interview/02_BEFIRST/02_BefirstGroupInterview.md","filePath":"zh-cn/Management2Extra/02_Interview/02_BEFIRST/02_BefirstGroupInterview.md"}'),p={name:"zh-cn/Management2Extra/02_Interview/02_BEFIRST/02_BefirstGroupInterview.md"};function a(g,r,e,i,T,O){return n(),o("div",null,[...r[0]||(r[0]=[s('<p>Group Interview</p><h1 id="be-first" tabindex="-1">BE:FIRST <a class="header-anchor" href="#be-first" aria-label="Permalink to &quot;BE:FIRST&quot;">​</a></h1><h3 id="持续把-最好的音乐-带给大家——be-first的自觉与责任" tabindex="-1">持续把“最好的音乐”带给大家——BE:FIRST的自觉与责任 <a class="header-anchor" href="#持续把-最好的音乐-带给大家——be-first的自觉与责任" aria-label="Permalink to &quot;持续把“最好的音乐”带给大家——BE:FIRST的自觉与责任&quot;">​</a></h3><p>经过了首次巡演所积累的经验与自信，加上《Boom Boom Back》获得的热烈反响，七位成员对于“身为BE:FIRST”的使命感愈发强烈。那么，在全新单曲《Mainstream》中，他们想要高声宣告的究竟是什么呢？</p><p><br><br><br><br></p><p>9月13日发行的第4张单曲《Mainstream》，是一张从初始创作阶段就有成员参与制作的作品，同时也浓缩了7人各自的音乐根源。在音数精简、低音主导的节拍之上，展开的是7人极具压迫感的麦克风接力。这是一张明显跳脱J-POP既有框架的挑战性单曲。甚至可以说，它本身就是一种宣言：BE:FIRST所走的路，才是“Mainstream”。</p><p>从惊艳的预出道到现在整整两年。在经历了他们口中“这是我们真正想做的音乐的第一步”的《Boom Boom Back》（2023年2月发行）之后，BE:FIRST的状态，在这一刻明显完成了一次换挡。</p><p>————在3rd单曲《Smile Again》时，你们提到“因为通过专辑制作和巡演接触了各种不同的歌曲，所以成员之间开始更频繁地讨论‘真正想做的音乐’”。当时具体都聊了些什么？</p><p><strong>RYUHEI</strong> 随着我们越来越能明确感受到“BE:FIRST本身就很有原创性”这件事，成员之间就开始聊——“要不要把对自己的自由度再拉高一点？”也就是希望能从更底层参与到音乐制作中，去追求更纯粹的创作。我觉得，这种想法的增强，正是《Mainstream》诞生的契机。</p><p><strong>SOTA</strong> 在不断消化各种歌曲的过程中，我们慢慢看清了“自己真正想做的东西”，所以基本上一直都在聊这个。后来去韩国拍电影（《BE:the ONE》）的时候，我就跟日高社长说了“基于这些原因，我们想做这样的歌。”</p><p><strong>JUNON</strong> 然后日高社长就说：“那你们先整理一下参考曲吧。”于是大家就各自拿出很多歌来分享。</p><p><strong>MANATO</strong> 那也是我们第一次做那种“成员共享的播放列表”。一边把各自喜欢的东西丢进去，一边讨论 “如果是现在的我们，做这样的歌是不是更合适？”最后就慢慢确定了《Mainstream》的方向。这首歌是在不考虑立场、不考虑外界条件的前提下，最接近我们现在“最想做的音乐”的作品。同时，它又不只是“我们想做什么”这么简单，里面也融合了日高社长的想法和经验。各种平衡都调得非常好。</p><p><strong>SOTA</strong> 《Mainstream》的参考曲其实是我提的。我们这些从小听很多音乐长大的成员，心里“最正中央”的那种音乐，反而很多日本听众是不太知道的。所以我就想，能不能把这些音乐，加一点现在的感觉，用我们自己的方式重新表达出来，让大家发现它的魅力。也不是那种“单方面炫给你看我们爱听的音乐”，而是更像——“我们很喜欢这种音乐，一起玩吧。”</p><p><strong>LEO</strong> 不是去迎合某种“正确答案”的音乐，而是为了让我们自己认同的音乐。我觉得《Mainstream》就是这样的一首歌。</p><h2 id="be-first的-最佳-是什么" tabindex="-1">BE:FIRST的“最佳”是什么 <a class="header-anchor" href="#be-first的-最佳-是什么" aria-label="Permalink to &quot;BE:FIRST的“最佳”是什么&quot;">​</a></h2><p>————《Boom Boom Back》带有很浓的90年代嘻哈味道，也很体现你们的根源。这首歌被广泛接受，你们怎么看？</p><p><strong>JUNON</strong> 在单独巡演的追加场表演《Boom Boom Back》的时候，我就觉得，这种风格真的很适合BE:FIRST。我自己也很享受，成员们也都很开心。能在arena级别的专场里，把“我们真正想做的第一步”呈现出来，这件事意义很大。</p><p><strong>MANATO</strong> 像TikTok上有很多年轻人模仿我们的舞蹈，这种接近我们音乐根源的作品，比想象中更容易被大家接受。所以我们也开始聊，“既然这样，是不是可以攻势更强一点？”从这个角度来看，《Mainstream》就是把“根源”表达得更彻底的一首歌。</p><p>————《Mainstream》没有让7个人一起唱主歌副歌，这点很有挑战性。</p><p><strong>SOTA</strong> 确实。</p><p><strong>MANATO</strong> 听的人可能会想：“到底哪里是hook？”这种结构在现在的日本音乐里其实不太常见。但对我们来说，这反而是正是我们想做的核心。希望大家可以用不同的视角去听。</p><p><strong>RYOKI</strong> 这首歌音源已经很强了，但我觉得现场会更猛。有点像《Gifted.》，在不断现场表演的过程中，会越来越找到感觉、不断变化。我觉得这首歌也是那种能在现场逐渐“完成”的作品。</p><p><strong>LEO</strong> 从一开始，我就觉得BE:FIRST是一个独一无二的团体。所以我们不会去想“和别人比怎么样”，而是一直在想，对BE:FIRST来说，什么才是最好的？这次能从主打歌阶段就和日高社长一起决定方向，并以更接近“最佳状态”的形式发表作品，真的很开心。</p><p>————这次你们也参与了编曲和作词？</p><p><strong>MANATO</strong> 像是“这个声音换掉会怎么样”“这个段落要不要这样推进”，我们一直在反复这样试错。我们过去其实很少有“从0到1”的经验，所以这次真的学到了很多。</p><p><strong>SHUNTO</strong> 因为减少了音数，反而产生了一种之前没有的沉浸感。副歌一下子“打开”的感觉也很新鲜。</p><p><strong>SOTA</strong> 歌词里的“BE:FIRST感”，其实很多时候是从日高社长那里产生的。我们会想，他会怎么把我们的想法表达出来？这一点我们自己也很期待。在这个基础上，我们再去细调，比如“这里想用英文”“这里想用日文”。最终，《Mainstream》是大家从0开始不断试错，一起找到的答案。而且这次最重要的一点是，我们终于能说出“等一下！我们也想从0开始参与。”这件事真的很大。</p><p><strong>RYOKI</strong> 我有些地方会觉得“这里想多用一点英文”，所以也把自己的英文词写进去替换了一部分。但这首歌同时也保留了日语的魅力。如果能展现出一种自然切换两种语言的感觉，就太好了。</p><p><strong>RYUHEI</strong> 歌词里既有日高社长的意志，也包含了我们为什么选择这首歌作为主打的意义。我觉得信息量其实非常大。</p><h3 id="充满统一感的一作" tabindex="-1">充满统一感的一作 <a class="header-anchor" href="#充满统一感的一作" aria-label="Permalink to &quot;充满统一感的一作&quot;">​</a></h3><p>————开头那句带气声的“Mainstream”，是SHUNTO吗？</p><p><strong>SHUNTO</strong> 是我。</p><p>———首张专辑《BE:1》里收录的《Milli-Billi》也是，感觉你已经成“气声担当”了（笑）</p><p><strong>RYUHEI</strong> 这点真的很狡猾欸！ 他一开口，全场就被带走了（笑）。</p><p><strong>全员</strong> （笑）</p><p><strong>RYUHEI</strong> SHUNTO一口气，换来的应援量真的太夸张了（笑）。</p><p><strong>SHUNTO</strong> 演出允许观众喊声之后，这点真的感受很明显（笑）。</p><p><br><br><br></p><p><strong>这次不仅主打歌，连收录曲的选择也反映了成员的意见。最终选中的是《SOS》和《Grow Up》。</strong></p><p><strong>SOTA</strong> 在做完《Mainstream》之后再去做收录曲，因为我们对“音乐方向”的感知已经更清晰了，所以完成度也很高。这张单曲不仅是很重要的一步，也能很好地连接到接下来的作品。</p><p><strong>JUNON</strong> 以前是先定主打，再选收录。但这次的情况是“这几首里面，哪首当主打？”也就是说，每一首都有当主打的实力。所有的歌的反响都很好。</p><p><strong>LEO</strong> 对，这三首歌就是一种感觉，“这就是我们想做的音乐，请听。”甚至不太需要解释。</p><p><strong>SOTA</strong> 对，就是把我们喜欢的音乐，用日语的“Made in Japan”的方式做出来。</p><p><strong>SHUNTO</strong> 我当时听《SOS》的时候甚至会想：“欸？收录曲直接这样走R&amp;B路线？”以前我们的单曲通常三首风格都很不一样，但这次反而有一种统一感。而且我们在巡演中一直在说“还缺这种类型的歌”，这次是真的补上了。</p><p><strong>RYUHEI</strong> 我觉得这是一张方向非常清晰的单曲。如果大家能从《Boom Boom Back》一路听到这张，然后感觉到“BE:FIRST之后会越来越往自己想走的方向冲”那就太好了。</p><h3 id="从电影回顾自己的足迹" tabindex="-1">从电影回顾自己的足迹 <a class="header-anchor" href="#从电影回顾自己的足迹" aria-label="Permalink to &quot;从电影回顾自己的足迹&quot;">​</a></h3><p><strong>8月25日，第一部现场纪录片《BE: the ONE》上映。从试镜“THE FIRST”的影像到首次的个人巡演、成员的采访等，这是约2年半他们足迹的影像作品。</strong></p><p><strong>SOTA</strong> 我本来以为自己身在其中，看电影的时候会觉得有点不好意思，结果还是哭了。连很细小的片段都被收进去了，对我们来说真的像宝物一样。</p><p><strong>LEO</strong> 会让人很清楚地感觉到“原来我们是这样一路走到现在的。”在我们看中间剪辑版的时候，“这样的连接方式会改变意思，所以我觉得还是改变一下比较好”像这样提了一些剪辑上的建议（笑），算是带了一点我自己的“电影迷视角”，小小自豪一下。</p><p><strong>JUNON</strong> 看完之后，对第一次巡演又多了一层新的情绪。以前拍YouTube的「You&#39;re My&quot;BESTY&quot;」的幕后会比较闹，更多是“有趣”“开心”之类的情绪。但当这些“有趣”的部分被拿掉之后，看到我们认真努力的样子，反而更感动。尤其是最后一部分《Message》响起来那段，光是氛围就已经很戳了。在电影院看应该会更夸张。</p><p><strong>SHUNTO</strong> 是那种一波一波叠上来的感动呢。而且平时其实很少有机会直接听到BESTY的声音，这次能一个个真实地感受到他们的存在，那一段我最想哭。</p><p><strong>MANATO</strong> 这两年真的一晃就过去了，但很多事情一下子都想起来了。这既是我们能回到原点的作品，也会让了解我们的人感动，同时也会让人想“要不要了解一下BE:FIRST”。而且音效真的很讲究，现场感很强。</p><p><strong>RYOKI</strong> 因为把“上台前”和“表演”放在一起呈现，所以我觉得我们作为BE:FIRST的状态，其实很清楚。台上台下，我们本质没有变。只是每个瞬间，都全力投入自己的热量的七个人。从后台打闹到上台，其实那股能量是连着的，甚至是直接带上舞台的。这种感觉随处都有。如果大家能从中感受到我们最真实的样子，就好了。</p><p><strong>RYUHEI</strong> 《THE FIRST》的片段也有用到。如果用来比喻的话，那段经历已经沉淀到像“石油”一样的程度了。石油不是很珍贵吗？如果没有那段经历，就不会有现在的BE:FIRST。我到现在也觉得，那是人生中最珍贵的体验。</p><p><strong>LEO</strong> 没想到在韩国会被问到成员的第一印象呢（笑）。</p><p><strong>MANATO</strong> 真的是。</p><p><strong>LEO</strong> 不过也很开心啊。拍摄结束后，我得到了休息时间。从早到晚一直吃着好吃的饭（笑）。</p><p><strong>SOTA</strong> 分成两拨去购物。</p><p><strong>JUNON</strong> 我因为和朋友见面所以几乎没有和成员见面吧？</p><p><strong>LEO</strong> 不过，晚上不是一起吃饭了吗？</p><p><strong>JUNON</strong> 哦，是的！我没有见到MANATO。</p><p><strong>LEO</strong> MANATO去和朋友见面了。我也遇到了前辈，意外地觉得大家在韩国都有朋友。因为和成员聚一起吃饭购物，和在日本休息的时候没有太大的变化。不过，回国后吃的寿司是最好吃的。</p><p><strong>SOTA &amp; MANATO</strong> 完全如此。</p><p><strong>MANATO</strong> 从机场拖着行李箱直接就去了吧。总觉得很感动。</p><p><strong>LEO</strong> “想吃日本料理！”就这样。果然是日本制造呢。</p><p><strong>MANATO</strong> 什么意思？（笑）。</p><p><strong>LEO</strong> （笑）。我也是made in japan，《Mainstream》也是made in japan，果然还是日本好啊，这样的意思。</p><h2 id="作为舞台表演者的责任" tabindex="-1">作为舞台表演者的责任 <a class="header-anchor" href="#作为舞台表演者的责任" aria-label="Permalink to &quot;作为舞台表演者的责任&quot;">​</a></h2><p>在电影中，SKY-HI对他们说：“希望你们能成为能承担‘影响他人人生’这份责任的人，而且我相信你们可以。” 他们是怎么理解这句话的呢？</p><p><strong>RYUHEI</strong> 既然有人在期待我们的音乐，那我们就一定有责任。如果不仅能回应期待，还能带来超出预期的冲击，那整个团也会成长。日高社长说的我非常能理解，成为艺人之后背负了至今没有意识到的责任，但这绝对不是负担，我会积极的面对，好好地成长起来。</p><p><strong>SHUNTO</strong> 其实从出道一开始，日高社长就一直在说这份责任，我完全能理解他的意思。接下来的阶段要站上更多舞台，这次通过电影重新确认了一遍这件事的重要性。</p><p><strong>RYOKI</strong> 我觉得继续做自己不就是一种责任吗。比起状态良好的时候，越是身处逆境的时候，越要坚持做自己该做的事，证明自己的创造力。我觉得这一点很重要。</p><p><strong>LEO</strong> 就像我们是看着各种音乐人长大，才喜欢上音乐，开始以音乐家为目标一样。看着我们的言行举止，也一定会有人因为我们，会想“想成为这样的人”，也可能反过来，“不想变成那样的人”。既然站在被这么多人看到的位置上，就一定有责任。但更重要的是，有没有意识到这份责任，会带来完全不同的舞台。我觉得需要有一种想象力，“如果我做了这件事，会对别人产生什么影响？”我很理解日高社长说的话。而且正因为我们在努力成为那样的艺人， BE:FIRST的音乐才会打动这么多人。接下来，也必须继续这样走下去。做音乐之前更重要的是做人，这个道理并不难。</p><p><strong>SOTA</strong> 我想让喜欢音乐的人遇到更好的音乐，也让对音乐不太感兴趣的人产生兴趣，我想在人生中创造一个幸福的地方。我认为我们的任务是用音乐增加人们的幸福。所以我觉得只要埋头于音乐就可以了，但是为了创作出更好的音乐，每个人都不间断地磨练自己，成为出色的人也是义务。但是，最终传递的是音乐……这是很难的。</p><p>我希望喜欢音乐的人，能遇到更好的音乐；也希望原本对音乐不太感兴趣的人，也能因此开始喜欢。如果可以的话，希望音乐能成为他们人生中一个让人更幸福的空间。我觉得我们的角色就是用音乐给人创造幸福的空间。所以当然要沉浸在音乐里。但为了做出更好的音乐，每个人也必须不断打磨自己、成为更好的人。不过最终我们传达的，还是音乐本身。能做到这点确实很难。</p><p><strong>LEO</strong> 很难。</p><p><strong>SOTA</strong> 老实说，把最好的音乐带给大家，就是全部了。对吧？</p><p><strong>JUNON</strong> 我也这么想。</p><p><strong>LEO</strong> 是大前提。</p><p><strong>SOTA</strong> 嗯，这个话题我们也经常聊。因为我们都是看着那些“把音乐放在中心的人”长大的，所以也很想成为那样的人。</p>',80)])])}const B=t(p,[["render",a]]);export{E as __pageData,B as default};
